    val digitSum = n.toString().chars().map { it - '0'.toInt() }.sum()

    // Calculate the product of digits
    val digitProduct = n.toString().chars().map { it - '0'.toInt() }.fold(1L) { acc, digit -> acc * digit }

    // Check if n is divisible by the sum of the digits and the product of the digits
    return (digitSum + digitProduct).also { if (it == 0L) return false } == n % it == 0L
